import{_ as a,o as t,c as r,ag as i}from"./chunks/framework.1N8rnUr9.js";const g=JSON.parse('{"title":"Library Management","description":"","frontmatter":{},"headers":[],"relativePath":"features/library-management.md","filePath":"features/library-management.md","lastUpdated":1775898919000}'),o={name:"features/library-management.md"};function n(l,e,s,h,u,d){return t(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="library-management" tabindex="-1">Library Management <a class="header-anchor" href="#library-management" aria-label="Permalink to &quot;Library Management&quot;">​</a></h1><p>The <strong>Library</strong> is the central hub of TubeBay. It displays all the videos synchronized from your YouTube channel and provides the interface for mapping them to your WooCommerce products.</p><h2 id="the-video-grid" tabindex="-1">The Video Grid <a class="header-anchor" href="#the-video-grid" aria-label="Permalink to &quot;The Video Grid&quot;">​</a></h2><p>In the Library tab, you&#39;ll see a responsive grid of your YouTube videos. Each item includes:</p><ul><li><strong>Thumbnail:</strong> The high-quality thumbnail from YouTube.</li><li><strong>Title:</strong> The video title as it appears on YouTube.</li></ul><h2 id="searching-your-library" tabindex="-1">Searching Your Library <a class="header-anchor" href="#searching-your-library" aria-label="Permalink to &quot;Searching Your Library&quot;">​</a></h2><p>Use the search bar at the top of the Library to find specific videos by title. This search is performed against the local WordPress cache, making it instantaneous.</p><h2 id="manual-sync" tabindex="-1">Manual Sync <a class="header-anchor" href="#manual-sync" aria-label="Permalink to &quot;Manual Sync&quot;">​</a></h2><p>If you&#39;ve recently uploaded a video to YouTube and it hasn&#39;t appeared yet, click the <strong>Sync Library</strong> button at the top right of the Library page to trigger an immediate update.</p><h2 id="sorting-filtering" tabindex="-1">Sorting &amp; Filtering <a class="header-anchor" href="#sorting-filtering" aria-label="Permalink to &quot;Sorting &amp; Filtering&quot;">​</a></h2><p>To help you find the right content quickly, you can sort your library using the dropdown menu:</p><ul><li><strong>Recently Added:</strong> Shows your newest YouTube uploads first.</li><li><strong>Oldest First:</strong> View your channel&#39;s earliest content.</li><li><strong>Title (A-Z/Z-A):</strong> Sort alphabetically by video title.</li><li><strong>Most Viewed:</strong> Prioritize videos with the highest view counts on YouTube.</li></ul>',12)])])}const y=a(o,[["render",n]]);export{g as __pageData,y as default};
